/**
 * Fuzzy match result
 */
public struct FuzzyMatch {
    public var item: String
    public var score: UInt32
    public var indices: [UInt32]

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(item: String, score: UInt32, indices: [UInt32]) {
        self.item = item
        self.score = score
        self.indices = indices
    }
}

#if compiler(>=6)
extension FuzzyMatch: Sendable {}
#endif


extension FuzzyMatch: Equatable, Hashable {
    public static func ==(lhs: FuzzyMatch, rhs: FuzzyMatch) -> Bool {
        if lhs.item != rhs.item {
            return false
        }
        if lhs.score != rhs.score {
            return false
        }
        if lhs.indices != rhs.indices {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(item)
        hasher.combine(score)
        hasher.combine(indices)
    }
}



