/**
 * Terminal color enumeration
 */

public enum TerminalColor {
    
    case `default`
    case black
    case red
    case green
    case yellow
    case blue
    case magenta
    case cyan
    case white
    case brightBlack
    case brightRed
    case brightGreen
    case brightYellow
    case brightBlue
    case brightMagenta
    case brightCyan
    case brightWhite
    case indexed(UInt8
    )
    case rgb(UInt8,UInt8,UInt8
    )
}


