extension TerminalColor: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeTerminalColor: FfiConverterRustBuffer {
    typealias SwiftType = TerminalColor

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TerminalColor {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .`default`
        
        case 2: return .black
        
        case 3: return .red
        
        case 4: return .green
        
        case 5: return .yellow
        
        case 6: return .blue
        
        case 7: return .magenta
        
        case 8: return .cyan
        
        case 9: return .white
        
        case 10: return .brightBlack
        
        case 11: return .brightRed
        
        case 12: return .brightGreen
        
        case 13: return .brightYellow
        
        case 14: return .brightBlue
        
        case 15: return .brightMagenta
        
        case 16: return .brightCyan
        
        case 17: return .brightWhite
        
        case 18: return .indexed(try FfiConverterUInt8.read(from: &buf)
        )
        
        case 19: return .rgb(try FfiConverterUInt8.read(from: &buf), try FfiConverterUInt8.read(from: &buf), try FfiConverterUInt8.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: TerminalColor, into buf: inout [UInt8]) {
        switch value {
        
        
        case .`default`:
            writeInt(&buf, Int32(1))
        
        
        case .black:
            writeInt(&buf, Int32(2))
        
        
        case .red:
            writeInt(&buf, Int32(3))
        
        
        case .green:
            writeInt(&buf, Int32(4))
        
        
        case .yellow:
            writeInt(&buf, Int32(5))
        
        
        case .blue:
            writeInt(&buf, Int32(6))
        
        
        case .magenta:
            writeInt(&buf, Int32(7))
        
        
        case .cyan:
            writeInt(&buf, Int32(8))
        
        
        case .white:
            writeInt(&buf, Int32(9))
        
        
        case .brightBlack:
            writeInt(&buf, Int32(10))
        
        
        case .brightRed:
            writeInt(&buf, Int32(11))
        
        
        case .brightGreen:
            writeInt(&buf, Int32(12))
        
        
        case .brightYellow:
            writeInt(&buf, Int32(13))
        
        
        case .brightBlue:
            writeInt(&buf, Int32(14))
        
        
        case .brightMagenta:
            writeInt(&buf, Int32(15))
        
        
        case .brightCyan:
            writeInt(&buf, Int32(16))
        
        
        case .brightWhite:
            writeInt(&buf, Int32(17))
        
        
        case let .indexed(v1):
            writeInt(&buf, Int32(18))
            FfiConverterUInt8.write(v1, into: &buf)
            
        
        case let .rgb(v1,v2,v3):
            writeInt(&buf, Int32(19))
            FfiConverterUInt8.write(v1, into: &buf)
            FfiConverterUInt8.write(v2, into: &buf)
            FfiConverterUInt8.write(v3, into: &buf)
            
        }
    }
}


